    },
    "uuid": {
      "type": "string",
      "format": "uuid",
      "description": "UUID identifier"
    },
    "metadata": {
      "type": "object",
      "patternProperties": {
        "^[a-zA-Z_][a-zA-Z0-9_]*$": {
          "oneOf": [
