});

// For complex transactions, use proper connection management
router.post('/users/:id/transfer', async (req, res) => {
  const client = await pool.connect();
  const requestId = req.requestId;

  try {
    console.log(`[${requestId}] Starting transaction...`);

    await client.query('BEGIN');

    // Multiple related queries
    await client.query('UPDATE accounts SET balance = balance - $1 WHERE user_id = $2', 
      [req.body.amount, req.params.id]);

    await client.query('UPDATE accounts SET balance = balance + $1 WHERE user_id = $2', 
