      console.error(`[${requestId}] Rollback error:`, rollbackError.message);
    }

    res.status(500).json({ 
      error: 'Transaction failed',
      requestId: requestId 
    });
  } finally {
    // CRITICAL: Always release the client in finally block
    console.log(`[${requestId}] Releasing client...`);
    client.release();
  }
});

module.exports = router;
```

