            let mut next_guard = next_node.write().map_err(|_| {
                CacheError::EvictionError("Failed to acquire write lock on next node".to_string())
            })?;
            next_guard.prev = prev;
        } else {
            self.tail = prev;
        }

        Ok(())
    }

    fn add_to_front(&mut self, node: Arc<RwLock<Node<K, V>>>) -> Result<()> {
        let mut node_guard = node.write().map_err(|_| {
            CacheError::EvictionError("Failed to acquire write lock on node".to_string())
        })?;

        node_guard.prev = None;
        node_guard.next = self.head.clone();
        drop(node_guard);

        if let Some(old_head) = &self.head {
            let mut old_head_guard = old_head.write().map_err(|_| {
                CacheError::EvictionError("Failed to acquire write lock on old head".to_string())
            })?;
            old_head_guard.prev = Some(node.clone());
        } else {
            self.tail = Some(node.clone());
        }

        self.head = Some(node);
        Ok(())
    }

    fn remove_tail(&mut self) -> Result<Option<K>> {
        if let Some(tail_node) = self.tail.take() {
            let tail_guard = tail_node.read().map_err(|_| {
                CacheError::EvictionError("Failed to acquire read lock on tail".to_string())
            })?;

