        node_ref.prev = None;
        node_ref.next = self.head;

        if let Some(mut old_head) = self.head {
            old_head.as_mut().prev = Some(node);
        }

        self.head = Some(node);

        // If this is the first node, it's also the tail
        if self.tail.is_none() {
