interface CRDTOperation {
  id: OperationId;
  type: 'insert' | 'delete' | 'format';
  position: LogicalPosition;
  content?: string;
  attributes?: TextAttributes;
  timestamp: LogicalTimestamp;
  authorId: string;
}
