// WebSocket connection management
class WebSocketGateway {
  constructor() {
    this.connections = new Map(); // userId -> WebSocket
    this.documentSessions = new Map(); // documentId -> Set<userId>
  }

  async handleConnection(ws, userId) {
    this.connections.set(userId, ws);

    ws.on('message', async (data) => {
      const message = JSON.parse(data);
      await this.routeMessage(userId, message);
    });

    ws.on('close', () => {
      this.handleDisconnection(userId);
    });
  }

  async routeMessage(userId, message) {
    switch (message.type) {
      case 'JOIN_DOCUMENT':
        await this.joinDocument(userId, message.documentId);
        break;
      case 'OPERATION':
        await this.handleOperation(userId, message);
        break;
      case 'CURSOR_UPDATE':
        await this.broadcastCursor(userId, message);
        break;
    }
  }
}
