### 4.2 Collaboration Service

```go
// Core collaboration service in Go
type CollaborationService struct {
    documentStore DocumentStore
    operationLog  OperationLog
    broadcaster   MessageBroadcaster
    crdt         CRDTEngine
}

type Document struct {
    ID           string                 `json:"id"`
    Content      *CRDTDocument         `json:"content"`
    VectorClock  map[string]int64      `json:"vector_clock"`
    LastModified time.Time             `json:"last_modified"`
    Participants map[string]Participant `json:"participants"`
}

func (cs *CollaborationService) ApplyOperation(
    documentID string, 
    operation *Operation,
) (*Document, error) {
    // 1. Validate operation
    if err := cs.validateOperation(operation); err != nil {
        return nil, err
    }

    // 2. Apply CRDT operation
    doc, err := cs.documentStore.GetDocument(documentID)
    if err != nil {
        return nil, err
    }

    updatedDoc, err := cs.crdt.ApplyOperation(doc, operation)
    if err != nil {
        return nil, err
    }

    // 3. Persist operation
    if err := cs.operationLog.AppendOperation(documentID, operation); err != nil {
        return nil, err
    }

    // 4. Broadcast to participants
    cs.broadcaster.BroadcastOperation(documentID, operation)

    return updatedDoc, nil
}
```

### 4.3 CRDT Implementation

```typescript
// Simplified CRDT implementation for text
class TextCRDT {
  private operations: Map<string, CRDTOperation> = new Map();
  private vectorClock: VectorClock = new VectorClock();

  insert(position: number, content: string, authorId: string): CRDTOperation {
    const operation: CRDTOperation = {
      id: this.generateOperationId(),
      type: 'insert',
      position: this.getLogicalPosition(position),
      content,
      timestamp: this.vectorClock.increment(authorId),
      authorId
    };

    this.applyOperation(operation);
    return operation;
  }

  delete(position: number, length: number, authorId: string): CRDTOperation {
    const operation: CRDTOperation = {
      id: this.generateOperationId(),
      type: 'delete',
      position: this.getLogicalPosition(position),
      length,
      timestamp: this.vectorClock.increment(authorId),
      authorId
    };

    this.applyOperation(operation);
    return operation;
  }

  merge(remoteOperations: CRDTOperation[]): void {
    // Sort operations by logical timestamp
    const sortedOps = remoteOperations.sort((a, b) => 
      this.compareTimestamps(a.timestamp, b.timestamp)
    );

    for (const op of sortedOps) {
      if (!this.operations.has(op.id)) {
        this.applyOperation(op);
        this.vectorClock.update(op.timestamp);
      }
    }
  }

  private getLogicalPosition(physicalPos: number): LogicalPosition {
    // Convert physical position to logical position
    // This is crucial for CRDT correctness
    return new LogicalPosition(physicalPos, this.generatePositionId());
  }
}
