### 5.2 Caching Strategy

```go
// Redis-based caching layer
type CacheLayer struct {
    redisClient *redis.Client
    localCache  *sync.Map // L1 cache
}

func (c *CacheLayer) GetDocument(documentID string) (*Document, error) {
    // L1 cache check
    if doc, ok := c.localCache.Load(documentID); ok {
        return doc.(*Document), nil
    }

    // L2 cache (Redis) check
    cached, err := c.redisClient.Get(
        context.Background(), 
        fmt.Sprintf("doc:%s", documentID),
    ).Result()

    if err == nil {
        var doc Document
        if err := json.Unmarshal([]byte(cached), &doc); err == nil {
            c.localCache.Store(documentID, &doc)
            return &doc, nil
        }
    }

    return nil, ErrCacheNotFound
}

func (c *CacheLayer) SetDocument(doc *Document) error {
    // Update L1 cache
    c.localCache.Store(doc.ID, doc)

    // Update L2 cache with TTL
    data, err := json.Marshal(doc)
    if err != nil {
        return err
    }

    return c.redisClient.Set(
        context.Background(),
        fmt.Sprintf("doc:%s", doc.ID),
        data,
        time.Hour, // 1 hour TTL
    ).Err()
}
```

### 5.3 Data Consistency Strategy

```go
// Event sourcing for operation log
type OperationLog struct {
    db     *sql.DB
    kafka  *kafka.Producer
}

func (ol *OperationLog) AppendOperation(
    documentID string, 
    operation *Operation,
) error {
    tx, err := ol.db.Begin()
    if err != nil {
        return err
    }
    defer tx.Rollback()

    // 1. Insert operation to database
    _, err = tx.Exec(`
        INSERT INTO document_operations 
        (id, document_id, operation_data, author_id, logical_timestamp)
        VALUES ($1, $2, $3, $4, $5)
    `, operation.ID, documentID, operation.Data, 
       operation.AuthorID, operation.Timestamp)

    if err != nil {
        return err
    }

    // 2. Publish to Kafka for real-time distribution
    message := &kafka.Message{
        Topic: "document-operations",
        Key:   []byte(documentID),
        Value: operation.Serialize(),
    }

    if err := ol.kafka.Produce(message, nil); err != nil {
        return err
    }

    return tx.Commit()
}
```

